'use client'

import { useEffect, useRef } from 'react'

const REAL_IMGS = ["data:image/jpeg;base64,", "data:image/jpeg;base64,", "data:image/jpeg;base64,", "data:image/jpeg;base64,", "data:image/jpeg;base64,", "data:image/jpeg;base64,", "data:image/jpeg;base64,", "data:image/jpeg;base64,", "data:image/jpeg;base64,", "data:image/jpeg;base64,"];

const cards = [{"w": 260, "h": 345, "y": 8}, {"w": 210, "h": 265, "y": 300}, {"w": 310, "h": 250, "y": 130}, {"w": 200, "h": 285, "y": 310}, {"w": 275, "h": 355, "y": 15}, {"w": 240, "h": 192, "y": 355}, {"w": 225, "h": 300, "y": 45}, {"w": 320, "h": 260, "y": 195}, {"w": 200, "h": 268, "y": 22}, {"w": 252, "h": 335, "y": 245}];
const gaps  = [60, 95, 45, 80, 35, 70, 90, 50, 75, 55];
const SPEED = 0.9

export default function ReelBanner() {
  const containerRef = useRef<HTMLDivElement>(null)

  useEffect(() => {
    const container = containerRef.current
    if (!container) return

    let paused = false
    let animId: number

    const els = cards.map((c, i) => {
      const div = document.createElement('div')
      div.className = 'sm-card-reel'
      div.style.position = 'absolute'
      div.style.borderRadius = '3px'
      div.style.overflow = 'hidden'
      div.style.boxShadow = '0 2px 18px rgba(0,0,0,0.09)'
      div.style.width = c.w + 'px'
      div.style.height = c.h + 'px'
      div.style.top = c.y + 'px'
      const img = document.createElement('img')
      img.src = REAL_IMGS[i % REAL_IMGS.length]
      img.alt = ''
      img.style.width = '100%'
      img.style.height = '100%'
      img.style.objectFit = 'cover'
      img.style.display = 'block'
      div.appendChild(img)
      container.appendChild(div)
      return div
    })

    let x = 10
    const positions = cards.map((c, i) => {
      const pos = x
      x += c.w + gaps[i % gaps.length]
      return pos
    })

    els.forEach((el, i) => { el.style.left = positions[i] + 'px' })

    function animate() {
      if (!paused) {
        positions.forEach((pos, i) => {
          positions[i] -= SPEED
          if (positions[i] + cards[i].w < 0) {
            const maxRight = Math.max(...positions.map((p, j) => p + cards[j].w))
            positions[i] = maxRight + gaps[i % gaps.length]
          }
          els[i].style.left = positions[i] + 'px'
        })
      }
      animId = requestAnimationFrame(animate)
    }

    animate()
    const toggle = () => { paused = !paused }
    container.addEventListener('click', toggle)

    return () => {
      cancelAnimationFrame(animId)
      container.removeEventListener('click', toggle)
      while (container.firstChild) container.removeChild(container.firstChild)
    }
  }, [])

  return (
    <div
      ref={containerRef}
      style={{
        width: '100%',
        background: '#F2EDE4',
        height: '600px',
        overflow: 'hidden',
        position: 'relative',
        cursor: 'pointer',
        borderRadius: '4px',
      }}
    />
  )
}
